        }
        annotations[LastAppliedConfigAnnotation] = value
        if err := apimachineryvalidation.ValidateAnnotationsSize(annotations); err != nil {
                delete(annotations, LastAppliedConfigAnnotation)
        }
        accessor.SetAnnotations(annotations)
        return nil
}

